+
+      const result = await d.render({ format: "excalidraw" });
+      const els = result.json.elements;
+
+      // Find the group rectangle
+      const group = els.find(e => e.type === "rectangle" && e.strokeStyle === "dashed" && e.backgroundColor === "transparent");
